class Solution(object):
    def minSwapsCouples(self, row):
        n = len(row) // 2
        parent = list(range(n))

        def find(x):
            if parent[x]!= x:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            parent[find(x)] = find(y)

        for i in range(0, len(row), 2):
            union(row[i] // 2, row[i + 1] // 2)

        return len(row) // 2 - sum(find(x) == x for x in parent)

