class Solution(object):
    def findRedundantDirectedConnection(self, edges):
        n = len(edges)
        parent = list(range(n + 1))
        redundant = None

        def find(x):
            if parent[x]!= x:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            nonlocal redundant
            p1, p2 = find(x), find(y)
            if p1 == p2:
                redundant = [x, y]
            else:
                parent[p2] = p1

        for x, y in edges:
            union(x, y)

        for x, y in edges:
            if x!= y and find(x) == find(y):
                return [x, y]

        return redundant

