class Solution(object):
    def cherryPickup(self, grid):
        n = len(grid)
        dp = [[-float('inf')]*n for _ in range(n)]
        dp[n-1][n-1] = grid[n-1][n-1]

        # start from bottom right, moving towards top left
        for i in range(n-1, -1, -1):
            for j in range(n-1, -1, -1):
                # if it's the destination, we can only move to the right or up
                if i == n-1 and j == n-1:
                    dp[i][j] = max(dp[i+1][j], dp[i][j+1]) + grid[i][j]
                # if it's not the destination, we can move to the right, up, or diagonally
                else:
                    dp[i][j] = max(dp[i+1][j], dp[i][j+1], dp[i+1][j+1]) + grid[i][j]

        # start from top left, moving towards bottom right
        res = dp[0][0]
        for i in range(n):
            for j in range(n):
                # if it's the starting point, we can only move to the left or down
                if i == 0 and j == 0:
                    res = max(res, dp[i][j+1], dp[i+1][j])
                # if it's not the starting point, we can move to the left, down, or diagonally
                else:
                    res = max(res, dp[i][j+1], dp[i+1][j], dp[i+1][j+1])

        return res

