            if not 0 <= i < m or not 0 <= j < n or board[i][j]!= word[ind]:
                return False
            if ind == len(word) - 1:
                return True
            tmp, board[i][j] = board[i][j], '/'
            res = any(dfs(ind + 1, i + x, j + y) for x, y in [(0, 1), (0, -1), (1, 0), (-1, 0)] if 0 <= i + x < m and 0 <= j + y < n)
            board[i][j] = tmp
            return res

        m, n = len(board), len(board[0])
        return any(dfs(0, i, j) for i in range(m) for j in range(n))

